      "keystrokes": "cd /app && python3 - <<'PY'\nfrom pathlib import Path\nimport struct\ndata=Path('mystery').read_bytes()\nfor start,end,lbl in [(0x480000,0x4800c0,'rodata constants'),(0x485a40,0x485c00,'data constants')]:\n    print('---',lbl)\n    for i in range(start,end,16):\n        row=data[i:i+16]\n        hexs=' '.join(f'{x:02x}' for x in row)\n        ascii=''.join(chr(x) if 32<=x<127 else '.' for x in row)\n        fs=[]\n        for j in range(0,len(row)-3,4):\n            f=struct.unpack('<f',row[j:j+4])[0]\n            if abs(f)>1e-6 and abs(f)<1e3:\n                fs.append(f'+{j}={f:.7g}')\n        print(f'{i:08x}: {hexs:<48} {ascii}' + (' | '+' '.join(fs) if fs else ''))\nPY\n",
      "duration": 1.0
    }
  ]
